import{_ as t,o as a,c as r,ag as i}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"explicit-external-state","description":"","frontmatter":{"title":"explicit-external-state","concept":"显式外部状态记忆","concept_id":"explicit-external-state","aliases":["External State Files"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] 三省六部幻觉：为什么_虚拟公司_式多Agent架构在工程上不成立.md"],"related_concepts":["[[agent-harness-pattern]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/explicit-external-state.md","filePath":"wiki/concepts/explicit-external-state.md","lastUpdated":null}'),n={name:"wiki/concepts/explicit-external-state.md"};function l(c,e,s,o,p,d){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="显式外部状态记忆-explicit-external-state" tabindex="-1">显式外部状态记忆 (Explicit External State) <a class="header-anchor" href="#显式外部状态记忆-explicit-external-state" aria-label="Permalink to &quot;显式外部状态记忆 (Explicit External State)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在执行长周期或多会话任务时，强制要求 Agent 将当前的任务进度、结论和避坑指南写入到持久化的物理文件（如 <code>progress.txt</code> 或 <code>spec.md</code>），以此作为推理连续性的锚点。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>对抗推理漂移 (Reasoning Drift)</strong>：大语言模型在超长上下文中极易“前言不搭后语”。正确的做法是把意图从聊天记录中抽出，转化为文件上的代码或文本变动。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - 三省六部幻觉：为什么_虚拟公司_式多Agent架构在工程上不成立.html">[Agent_Architecture] 三省六部幻觉：为什么_虚拟公司_式多Agent架构在工程上不成立.md</a>）</li><li><strong>分立的状态维度</strong>：一个好的外置状态文件必须包括：确定的目标（防漂移）、当前状态（反映进度）、已完成步骤的历史（不可覆盖式记录）、已知的坑（防重复踩）。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>放弃“试图把所有 Context 喂给最新的一代长文本模型”的想法。当需要开发一个完整的 App 时，让你的 Agent 系统学会阅读并持续重写物理形式的日志和设计规范，所有的逻辑连续性必须“可见”。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/agent-harness-pattern.html">agent-harness-pattern</a> — 依靠这些生成的文件，人类构建器才能判断系统是否应当被挂起或纠正。</li></ul>',9)])])}const x=t(n,[["render",l]]);export{_ as __pageData,x as default};
